exports.getProductAssignments = async (req, res) => {
  try {
    const data = await ProductAssignmentService.getAssignments(req.params.itemId);
    res.send({ status: true, roles: ProductAssignmentService.roles, data });
  } catch (err) {
    res.status(err.statusCode || 500).send({
      status: false,
      message: err.message || "Error fetching product assignments."
    });
  }
};

exports.setProductAssignments = async (req, res) => {
  try {
    const userInfo = await getUserInfo(req.headers.authorization);
    const assignments = req.body.assignments ?? req.body;
    const data = await ProductAssignmentService.setAssignments(
      req.params.itemId,
      assignments,
      userInfo?.user_id ?? userInfo?.id
    );
    res.send({ status: true, roles: ProductAssignmentService.roles, data });
  } catch (err) {
    res.status(err.statusCode || 500).send({
      status: false,
      message: err.message || "Error updating product assignments."
    });
  }
};

exports.clearProductAssignment = async (req, res) => {
  try {
    const deleted = await ProductAssignmentService.clearAssignment(req.params.itemId, req.params.role);
    res.send({ status: true, deleted });
  } catch (err) {
    res.status(err.statusCode || 500).send({
      status: false,
      message: err.message || "Error clearing product assignment."
    });
  }
};

