501	
502	          //Convert licensor code to full name
503	          if (newData?.from?.toLowerCase() !== 'pop') newData.from = this.merchGroups.find(g => g?.mgTypeDesc?.toLowerCase().replace(' ', '') === 'licensor')?.merchGroups.find(group => group?.mg_code === row?.licensor)?.mg_desc
504	          mergedData.push(JSON.parse(JSON.stringify(newData)))
