634	    function percentFormatter(params) {
635	      if (params.value) {
636	        return formatNumber(params.value) + '%';
637	      }
638	    }
639	
640	    function mapHeaders(colHeaders, groups) {
641	      mapHeaderValues(colHeaders, groups, 'property')
642	      mapHeaderValues(colHeaders, groups, 'material')
643	      mapHeaderValues(colHeaders, groups, 'construction')
644	      mapHeaderValues(colHeaders, groups, 'feature')
645	      mapHeaderValues(colHeaders, groups, 'size')
646	      mapHeaderValues(colHeaders, groups, 'licensor')
647	      mapHeaderValues(colHeaders, groups, 'subformat')
648	    }
649	
650	    function mapHeaderValues(colHeaders, groups, header) {
651	      const column = colHeaders.find(h => h?.field === header);
652	
653	      if (!column) return;
654	
655	      column.valueGetter = (m) => {
656	        if ((header === 'licensor' || header === 'property') && isSpruceNonLicItem(m?.data)) {
657	          return 'NON-LIC';
658	        }
659	
660	        // Step 1: Collect ALL merchGroups that match the header type
661	        const allMerchGroups: any[] = [];
662	        groups.forEach(g => {
663	          const mgTypeDesc = g?.mgTypeDesc?.toLowerCase().replace(/\s/g, '');
664	          if (mgTypeDesc === header && g?.merchGroups?.length) {
665	            allMerchGroups.push(...g.merchGroups);
666	          }
667	        });
668	
669	        if (!allMerchGroups.length) return null;
670	
671	        // Step 2: Find the correct group based on conditions
672	        if (m?.data?.is_item_old) {
673	          const matchedGroup = allMerchGroups.find(
674	            group =>
675	              group?.mg_code === m?.data[header] &&
676	              new Date(group?.createdTime).getFullYear() !== 2025
677	          );
678	          return matchedGroup?.mg_desc;
679	        } else {
680	          const matchedGroup = allMerchGroups.find(
681	            group => group?.mg_id === m?.data[`${header}_id`]
682	          );
683	          return matchedGroup?.mg_desc;
684	        }
685	      };
686	    }
687	
688	    function isSpruceNonLicItem(row) {
689	      return Number(row?.div_code_fk) === 9;
690	    }
691	
692	    function formatNumber(number) {
693	      // this puts commas into the number eg 1000 goes to 1,000,
694	      // i pulled this from stack overflow, i have no idea how it works
695	      return Number.parseFloat(number).toFixed(2).toString().replace(/(\d)(?=(\d{3})+(?!\d))/g, "$1,");
696	    }
697	
698	    function formatDate(input) {
699	      if (input == null) return ''
700	      if (input.includes("-")) {
701	        var datePart = input.match(/\d+/g),
702	          year = datePart[0].substring(), // get only two digits
703	          month = datePart[1], day = datePart[2];
704	        return month + '/' + day + '/' + year;
705	      } else {
706	        return input
707	      }
708	    }
