1014	  dateComparator(date1, date2, nodeA, nodeB, isInverted) {
1015	    function formatDate(input) {
1016	      if (input == null) return ''
1017	      if (input.includes("-")) {
1018	        var datePart = input.match(/\d+/g),
1019	          year = datePart[0].substring(), // get only two digits
1020	          month = datePart[1], day = datePart[2];
1021	        return month + '/' + day + '/' + year;
1022	      } else {
1023	        return input
1024	      }
1025	    }
1026	
1027	    function monthToComparableNumber(date) {
1028	
1029	      if (date === undefined || date === null || date.length !== 10) {
1030	        return date.length;
1031	      }
1032	      var yearNumber = date.substring(6, 10);
1033	      var dayNumber = date.substring(3, 5);
1034	      var monthNumber = date.substring(0, 2);
1035	      var result = yearNumber * 10000 + monthNumber * 100 + dayNumber;
1036	      return result;
1037	    }
1038	
1039	
1040	    date1 = formatDate(date1)
1041	
1042	    date2 = formatDate(date2)
1043	
1044	    var date1Number = monthToComparableNumber(date1);
1045	    var date2Number = monthToComparableNumber(date2);
1046	    if (date1Number === null && date2Number === null) {
1047	      return 0;
1048	    }
1049	    if (date1Number === null) {
1050	      return -1;
1051	    }
1052	    if (date2Number === null) {
1053	      return 1;
1054	    }
1055	    return date1Number - date2Number;
1056	  }
