  private saveStateToSession(): void {
    if (!this.gridApi) return;
    const state = {
      columnState: this.gridApi.getColumnState(),
      filterModel: this.gridApi.getFilterModel(),
      timestamp: Date.now()
    };
    sessionStorage.setItem('gridState_itemLibrary', JSON.stringify(state));
