  private restoreStateFromSession(): void {
    if (!this.gridApi) return;
    const saved = sessionStorage.getItem('gridState_itemLibrary');
    if (saved) {
      try {
        const state = JSON.parse(saved);
        if (state.columnState) {
          this.gridApi?.applyColumnState({ state: state.columnState, applyOrder: true });
        }
        if (state.filterModel && Object.keys(state.filterModel).length > 0) {
          this.gridApi?.setFilterModel(state.filterModel);
        }
      } catch (e) {
        console.warn('Failed to restore grid state from session:', e);
      }
    }
  }

