            || element.colId == this.getMasterFiledName('gen_mddp_sell_price') || element.colId == this.getMasterFiledName('gen_mddp_margin') || element.colId == this.getMasterFiledName('gen_mddp_price_sales')) {
            element.hide = false
          }
        });
        this.gridApi.applyColumnState({ state: columns, applyOrder: true });
      }
    } else {
      //show lic columns and gen columns
      columns = this.gridApi.getColumnState();
      columns.forEach(element => {
        if (element.colId == this.getMasterFiledName('gen_fob_sell_price') || element.colId == this.getMasterFiledName('gen_fob_margin') || element.colId == this.getMasterFiledName('gen_fob_price_sales')
          || element.colId == this.getMasterFiledName('gen_poe_sell_price') || element.colId == this.getMasterFiledName('gen_poe_margin') || element.colId == this.getMasterFiledName('gen_poe_price_sales')
          || element.colId == this.getMasterFiledName('gen_whse_sell_price') || element.colId == this.getMasterFiledName('gen_whse_margin') || element.colId == this.getMasterFiledName('gen_whse_price_sales')
          || element.colId == this.getMasterFiledName('gen_mddp_sell_price') || element.colId == this.getMasterFiledName('gen_mddp_margin') || element.colId == this.getMasterFiledName('gen_mddp_price_sales')
          || element.colId == this.getMasterFiledName('lic_fob_sell_price') || element.colId == this.getMasterFiledName('lic_fob_margin') || element.colId == this.getMasterFiledName('lic_fob_price_sales')
          || element.colId == this.getMasterFiledName('lic_poe_sell_price') || element.colId == this.getMasterFiledName('lic_poe_margin') || element.colId == this.getMasterFiledName('lic_poe_price_sales')
          || element.colId == this.getMasterFiledName('lic_whse_sell_price') || element.colId == this.getMasterFiledName('lic_whse_margin') || element.colId == this.getMasterFiledName('lic_whse_price_sales')
          || element.colId == this.getMasterFiledName('lic_mddp_sell_price') || element.colId == this.getMasterFiledName('lic_mddp_margin') || element.colId == this.getMasterFiledName('lic_mddp_price_sales')
          || element.colId == this.getMasterFiledName('lic_fob_royalty') || element.colId == this.getMasterFiledName('lic_whse_royalty') || element.colId == this.getMasterFiledName('lic_poe_royalty') || element.colId == this.getMasterFiledName('lic_mddp_royalty')) {
          element.hide = false
        }
      });
    }

    this.gridApi.applyColumnState({ state: columns, applyOrder: true });
    const divisionCodeIds = this.selectedDivisionCode?.map(d => d.divCode_id) || [];
    this.serverSideDatasource = this.createServerSideDatasource(divisionCodeIds);
    this.gridApi.setGridOption("serverSideDatasource", this.serverSideDatasource);
  }

  setPrinterFriendly(api) {
    const eGridDiv = <HTMLElement>document.querySelector('#myGrid');
    eGridDiv.style.height = '';
    api.setDomLayout('print');
  }

  onToggleAll() {

    switch (this.toggleStatus) {
      case false: {
        this.gridApi.expandAll();
        this.toggleStatus = true;
        break;
      }
      case true: {
        this.gridApi.collapseAll();
        this.toggleStatus = false;
        break;
      }
    }
  }

  onCellContextMenu(event) {
  }

  findMGfromArray(value, data) {
    if (data.array) {
      let merchGroups = data
      merchGroups.array.forEach(element => {
        if (element.mg_id == parseInt(merchGroups.data)) {
          return element.mg_desc
        }
      });
    } else if (data.title) {
      return data.title;
    } else {
      return data.data;
    }
  }

  async onReminder() {
    let selectedRowData = this.gridApi.getSelectedNodes()
    for (var i = 0; selectedRowData.length > i; i++) {
      if (selectedRowData[i].data) {
        if (selectedRowData[i].data.Vendors) {
          for (var j = 0; selectedRowData[i].data.Vendors.length > j; j++) {
            if (selectedRowData[i].data.Vendors[j].req_status == null) {
              try {
                const res: any = await this.itemService.sendPriceReq({ id: selectedRowData[i].data.Vendors[j].Vendor.id, rfqItem_priceCode: selectedRowData[i].data.Vendors[j].priceCode, sendEmail: true }).toPromise();
              } catch (err) {
                console.error('[ItemLibrary] priceCode, sendEmail: true }) failed:', err);
              }
            }
          }
        }
      }
    }
    this._snackBar.open('Reminder was sent successfully.', 'ok', {
      duration: 2000,
    })
  }

  toggleToolbarVisibility() {
    this.toolbarVisible = !this.toolbarVisible;
  }

  private decrementLoaderIfNeeded(): void {
    if (this.isInitialLoad) {
      this.isInitialLoad = false;
      this.loaderService.decrement();
    } else if (this.isDivisionChangeLoad) {
      this.isDivisionChangeLoad = false;
      this.loaderService.decrement();
    }
  }

  onChipsVisibilityChange(visible: boolean): void {
    this.hasActiveChips = visible;
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

}

export const ITEM_LIBRARY_COLUMN_HEADERS_CONFIG: any = {
    columnDefs: getItemColumnDefs()
  };

  function getItemColumnDefs() {
    const commonDefaults = {
      filter: 'agMultiColumnFilter',
      filterParams: {
        filters: [
          {
            filter: 'agTextColumnFilter',
        }
      ],
    },
      cellRenderer: null,
      hide: false,
      checkboxSelection: false,
      rowDrag: false,
      rowGroup: false,
      editable: false,
      cellEditor: null,
      // ✅ TOOLTIP SUPPORT
      tooltipValueGetter: (params) => params.value != null ? String(params.value) : '',
      headerTooltip: null
    };

    const addColumn = (
      field: string,
      headerName: string,
      colId: string,
      width: number,
      overrides: any = {}
    ) => ({
      field,
      headerName,
      colId,
      width,
      ...commonDefaults,
      ...overrides
    });

    return [
      addColumn('pic', 'Picture', 'pic', 150, {filter: false, cellRenderer: 'imageEditor'}),

      addColumn('item_name', 'Name', 'item_name', 285, { tooltipField: 'item_name' }),

      addColumn('refNum', 'Reference #', 'refNum', 175),

      addColumn('licensor', 'Licensor', 'licensor', 150),

      addColumn('season', 'Season', 'season', 150),

      addColumn('status', 'Status', 'status', 150, { cellEditor: 'autoCompelete'}),

      addColumn('itemNum', 'Item Num', 'itemNum', 150),

      addColumn('property', 'Property', 'property', 249),

      addColumn('material', 'Material', 'material', 250),

      addColumn('construction', 'Construction', 'construction', 250),

      addColumn('feature', 'Feature', 'feature', 250),

      addColumn('size', 'Size', 'size', 250, { cellEditor: 'autoCompelete'}),

      addColumn('DSN', 'Design #', 'dsn', 150)
    ];
  }

