import { AfterViewInit, Component, OnInit, ViewChild, ViewContainerRef } from '@angular/core';
import { ICellRendererParams } from "ag-grid-community";
import { AgEditorComponent } from "ag-grid-angular";
import { MatDatepickerInputEvent } from '@angular/material/datepicker';
import { FormControl } from '@angular/forms';
import { MatDialog } from '@angular/material/dialog';
import { imageEditorComponent } from '../imageEditor/imageEditor.component';
import { itemService } from '../../../helpers/services/main.service';
import { MatSnackBar } from '@angular/material/snack-bar';
import { ConfigService } from 'src/app/helpers/services/config.service';
import { HelperService } from 'src/app/helpers/services/helper.service';

export interface data {
  value: string;
}
/**
 * rfq-datepicker
 * created for apply filter on each column
 */

@Component({
    selector: 'image',
    templateUrl: 'image.component.html',
    styleUrls: ['image.component.scss'],
    standalone: false
})
export class imageComponent implements AgEditorComponent, AfterViewInit {
  params: ICellRendererParams;
  src: any;
  events: any
  noImageUrl: string;
  constructor(
    public dialog: MatDialog,
    private configService: ConfigService,
    private helperService: HelperService
  ) {
    this.noImageUrl = this.configService.NO_IMAGE_URL;
  }

  ngAfterViewInit() {

  }

  agInit(params: any): void {
    this.params = params;
    if (params.data.pic) {
      this.src = {
        FullSizePicture: this.helperService.buildPublicUrl(params.data.pic.FullSizePicture || this.noImageUrl),
        Thumbnail: this.helperService.buildPublicUrl(params.data.pic.Thumbnail || this.noImageUrl)
      };
    }
  }

  /* Component Editor Lifecycle methods */
  // the final value to send to the grid, on completion of editing
  getValue() {
    if (this.events == undefined) {
      return this.params.value;
    } else {
      return this.events;
    }

  }

  onImageEditor() {
    this.dialog.open(imageEditorComponent, {
      data: this.src,
      maxWidth: '95vw',
      maxHeight: '95vh'
    });
  }

  ngOnInit() {

  }


}

