import { Component } from '@angular/core';
import { ICellRendererAngularComp } from 'ag-grid-angular';
import { ICellRendererParams } from 'ag-grid-community';

export interface PillTone {
  bg: string;
  fg: string;
  dot: string;
}

const STATUS_TONES: Record<string, PillTone> = {
  concept:    { bg: '#f1eee9', fg: '#46454f', dot: '#76747f' },
  design:     { bg: '#ecebf6', fg: '#302e63', dot: '#3f3d86' },
  submitted:  { bg: '#f7efe0', fg: '#8a6312', dot: '#c08a2a' },
  approved:   { bg: '#e8f1ea', fg: '#2f6a45', dot: '#3f8a5b' },
  sampling:   { bg: '#f7ece2', fg: '#9a4f23', dot: '#c2662f' },
  production: { bg: '#ecebf6', fg: '#302e63', dot: '#3f3d86' },
  shelf:      { bg: '#e8f1ea', fg: '#2f6a45', dot: '#3f8a5b' },
  discont:    { bg: '#f7e7e4', fg: '#9a3a30', dot: '#bd5246' }
};

const STATUS_KEY_MAP: Record<string, string> = {
  'concept':       'concept',
  'in design':     'design',
  'submitted':     'submitted',
  'approved':      'approved',
  'in sampling':   'sampling',
  'production':    'production',
  'on shelf':      'shelf',
  'discontinued':  'discont'
};

@Component({
  selector: 'app-status-pill',
  templateUrl: './status-pill.component.html',
  styleUrls: ['./status-pill.component.scss'],
  standalone: false
})
export class StatusPillComponent implements ICellRendererAngularComp {
  label = '';
  tone: PillTone = STATUS_TONES['concept'];

  agInit(params: ICellRendererParams): void {
    this.label = String(params.value || '');
    const key = STATUS_KEY_MAP[this.label.toLowerCase().trim()] || 'concept';
    this.tone = STATUS_TONES[key];
  }

  refresh(params: ICellRendererParams): boolean {
    this.agInit(params);
    return true;
  }
}

