53	
54	    await this.itemService
55	      .getCustomGridLayout({ layout_name: 'Default', grid_id: this.gridId })
56	      .subscribe(async (colHeaders: any) => {
57	        colHeaders.forEach(element => {
58	          if (element.hide == false) {
59	            this.selectedHeaders.push(element.colId)
60	          }
61	        });
62	        this.colHeaders = colHeaders
63	
