81	      this._snakcbar.open('Grid is not ready yet.', 'close');
82	      return;
83	    }
84	    this.colHeaders.forEach(element => {
85	      if (element.colId == value.colId) {
86	        if (value.hide == true) {
87	          element.hide = false
88	        } else {
89	          element.hide = true
