92	    });
93	    const state = this.colHeaders.map((row) => toAgColumnState(row));
94	    this.gridApi.applyColumnState({ state });
95	
96	  }
97	  _filter(value: unknown) {
98	    const filterValue = (value == null ? '' : String(value)).toLowerCase();
99	    return this.colHeaders.filter(col =>
100	      (col.colId != null) && String(col.colId).toLowerCase().includes(filterValue)
101	    );
