import { UntypedFormControl } from '@angular/forms';
import { Observable } from 'rxjs';
import { map, startWith } from 'rxjs/operators';
import { Component, Input, ViewChild } from '@angular/core';
import { itemService } from '../../../helpers/services/main.service';
import { MatSelect } from '@angular/material/select';
import { MatSnackBar } from '@angular/material/snack-bar';

/** AG Grid ColumnState-compatible subset for applyColumnState */
function toAgColumnState(row: {
  colId?: string;
  hide?: boolean;
  pinned?: string | boolean | null;
  width?: number;
  flex?: number;
  sort?: 'asc' | 'desc' | null;
  sortIndex?: number | null;
}): Record<string, unknown> {
  const s: Record<string, unknown> = { colId: row.colId };
  if (row.hide !== undefined) s.hide = row.hide;
  if (row.pinned !== undefined && row.pinned !== null) s.pinned = row.pinned;
  if (row.width != null) s.width = row.width;
  if (row.flex != null) s.flex = row.flex;
  if (row.sort !== undefined) s.sort = row.sort;
  if (row.sortIndex != null) s.sortIndex = row.sortIndex;
  return s;
}

@Component({
    selector: 'layout-dropdown',
    templateUrl: 'layout-dropdown.component.html',
    styleUrls: ['layout-dropdown.component.scss'],
    standalone: false,
    host: { 'data-module': 'item_library' }
})
export class LayoutDropdownComponent {
  @Input() gridApi: any;
  /** Persisted layout key; must match parent (e.g. itemLibrary uses 'itemLibrary', RFQ uses 'rfq'). */
  @Input() gridId = 'rfq';
  @Input() selectedView: any;
  colHeaders: any = []
  filteredOptions: Observable<any[]>;
  selectedHeaders: any = []
  role: any
  inputControl = new UntypedFormControl();
  @ViewChild('select', { static: false }) selector: MatSelect
  constructor(private itemService: itemService, private _snakcbar: MatSnackBar) {

  }

  async ngOnInit() {

    await this.itemService
      .getCustomGridLayout({ layout_name: 'Default', grid_id: this.gridId })
      .subscribe(async (colHeaders: any) => {
        colHeaders.forEach(element => {
          if (element.hide == false) {
            this.selectedHeaders.push(element.colId)
          }
        });
        this.colHeaders = colHeaders

        this.filteredOptions = this.inputControl.valueChanges.pipe(
          startWith(''),
          map((value) => this._filter(value))
        );
      })
    try {
      const res: any = await this.itemService.verifyRole().toPromise();
      this.role = res.role

    } catch (err) {
      console.error('[LayoutDropdown] verifyRole failed:', err);
    }

  }

  async onSelect(value) {
    if (!this.gridApi?.applyColumnState) {
      this._snakcbar.open('Grid is not ready yet.', 'close');
      return;
    }
    this.colHeaders.forEach(element => {
      if (element.colId == value.colId) {
        if (value.hide == true) {
          element.hide = false
        } else {
          element.hide = true
        }
      }
    });
    const state = this.colHeaders.map((row) => toAgColumnState(row));
    this.gridApi.applyColumnState({ state });

  }
  _filter(value: unknown) {
    const filterValue = (value == null ? '' : String(value)).toLowerCase();
    return this.colHeaders.filter(col =>
      (col.colId != null) && String(col.colId).toLowerCase().includes(filterValue)
    );
  }
  async onClick(select: MatSelect) {
    if (!this.gridApi?.getColumnState) {
      this._snakcbar.open('Grid is not ready yet.', 'close');
      return;
    }

    this.selectedHeaders = []
    this.colHeaders = []

    const allState = this.gridApi.getColumnState();
    const colHeaders = allState.map((state, index) => ({
      colId: state.colId,
      hide: state.hide,
      pinned: state.pinned,
      width: state.width,
      flex: state.flex,
      sort: state.sort,
      sortIndex: state.sortIndex,
      order: index,
      layout_name: this.selectedView?.layout_name,
    }));
    colHeaders.forEach(element => {
      if (element.hide == false) {
        this.selectedHeaders.push(element.colId)
      }
    });
    this.colHeaders = colHeaders

    this.filteredOptions = this.inputControl.valueChanges.pipe(
      startWith(''),
      map((value) => this._filter(value))
    );

    setTimeout(() => select.open(), 0);
  }
  async onSave() {
    if (!this.gridApi?.getColumnState) {
      this._snakcbar.open('Grid is not ready yet.', 'close');
      return;
    }
    if (this.selectedView.layout_name != 'Default' && this.selectedView.layout_name != null || this.selectedView.layout_name != null && this.role == 'admin') {
      const allState = this.gridApi.getColumnState();
      const orderAndVisibilityState = allState.map((state, index) => ({
        colId: state.colId,
        hide: state.hide,
        pinned: state.pinned,
        width: state.width,
        order: index,
        layout_name: this.selectedView.layout_name,
        field: state.colId,
        grid_id: this.gridId
      }));
      try {
        const data: any = await this.itemService.saveGridLayout(orderAndVisibilityState).toPromise();
        this._snakcbar.open(`Current view was saved successfully.`, 'close')
      } catch (err) {
        console.error('[LayoutDropdown] saveGridLayout failed:', err);
      }
    } else {
      this._snakcbar.open(`You can't save on Default view. Please select a diffrent view or create a new one.`, 'close')
    }
  }
}

