getRowHeight(params: RowHeightParams): number | undefined | null

getRowHeight(params) {
  if (params.node && params.node.detail) {
    if (window['role'] != 'vendor') {
      var offset = 80;
    } else {
      var offset = 26.4;
    }

    var allDetailRowHeight =
      params.data.Vendors.length *
      this.gridApi.getSizesForCurrentTheme().rowHeight;
    var gridSizes = this.gridApi.getSizesForCurrentTheme();
    return (
      allDetailRowHeight +
      ((gridSizes && gridSizes.headerHeight) || 0) +
      offset
    );
  }
};

