setLayout(l: 'filmstrip' | 'split'): void {
  this.layout = l;
  this.hoverItem = null;
  if (l === 'split' && this.rowData.length) {
    this.activeItem = this.activeItem || this.rowData[0];
    if (this.activeItem?.pic?.Thumbnail) {
      this.activeItemImgSrc = this.helperService.buildPublicUrl(this.activeItem.pic.Thumbnail);
    }
  }
}

setView(v: 'table' | 'gallery'): void {
  this.view = v;
  this.hoverItem = null;
}

setDensity(d: 'comfortable' | 'compact'): void {
  this.density = d;
  this.gridApi?.resetRowHeights();
}

toggleColumnItem(item: { colId: string; label: string; visible: boolean }): void {
  item.visible = !item.visible;
  this.gridApi?.setColumnVisible(item.colId, item.visible);
}

syncColumnMenuFromGrid(): void {
  if (!this.gridApi) return;
  const state = this.gridApi.getColumnState();
  state.forEach(cs => {
    const found = this.columnMenuItems.find(c => c.colId === cs.colId);
    if (found) found.visible = !cs.hide;
  });
}

buildImgUrl(url: string): string {
  return this.helperService.buildPublicUrl(url);
}

get hoverTileGradient(): string {
  const str = String(this.hoverItem?.property || this.hoverItem?.property_id || '');
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  const h = Math.abs(hash) % 360;
  return `linear-gradient(150deg, hsl(${h} 46% 95%), hsl(${h} 40% 87%))`;
}

onGallerySelectionChange(event: { item: any; checked: boolean }): void {
  if (event.checked) {
    this.gallerySelectedIds.add(event.item.id);
  } else {
    this.gallerySelectedIds.delete(event.item.id);
  }
  this.gallerySelectedIds = new Set(this.gallerySelectedIds);
}

onGalleryItemOpen(item: any): void {
  if (item?.id) {
    this.router.navigate([`/apps/itemDetail/${item.id}`]);
  }
}

