@use "../../../styles" as styles;

/* ── Design tokens ───────────────────────────────────────────────────────── */
:host {
  @include styles.page-component-layout;
  display: flex;
  flex-direction: column;
  height: 100%;
  overflow: hidden;
  font-family: 'Hanken Grotesk', system-ui, sans-serif;

  --ink:       #1c1b22;
  --ink-2:     #46454f;
  --ink-3:     #76747f;
  --ink-4:     #a8a6af;
  --line:      #e7e3dd;
  --line-2:    #f0ece6;
  --paper:     #ffffff;
  --bg:        #f5f3ef;
  --chip:      #f1eee9;
  --brand:     #3f3d86;
  --brand-700: #302e63;
  --brand-50:  #ecebf6;
  --accent:    #c2662f;
  --accent-700:#9a4f23;
  --accent-50: #f7ece2;
}

/* ── Command bar ─────────────────────────────────────────────────────────── */
.command-bar {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  padding: 10px 20px;
  background: var(--paper);
  border-bottom: 1px solid var(--line);
  flex-shrink: 0;
  min-height: 56px;
  box-sizing: border-box;
}

.cmd-brand {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.brand-tile {
  width: 28px;
  height: 28px;
  border-radius: 8px;
  background: var(--brand);
  display: flex;
  align-items: center;
  justify-content: center;

  mat-icon {
    color: #fff;
    font-size: 16px;
    width: 16px;
    height: 16px;
  }
}

.brand-title {
  font-size: 15px;
  font-weight: 800;
  letter-spacing: -0.02em;
  color: var(--ink);
  white-space: nowrap;
}

.cmd-vr {
  width: 1px;
  height: 24px;
  background: var(--line);
  flex-shrink: 0;
  margin: 0 2px;
}

.cmd-create {
  background: var(--accent) !important;
  color: #fff !important;
  border-radius: 9px !important;
  height: 36px;
  padding: 0 14px;
  font-size: 13.5px;
  font-weight: 600;
  flex-shrink: 0;
  box-shadow: none !important;

  mat-icon {
    font-size: 18px;
    width: 18px;
    height: 18px;
    margin-right: 4px;
  }

  &:hover { background: var(--accent-700) !important; }
}

.cmd-search {
  flex: 1 1 180px;
  min-width: 150px;
  max-width: 360px;
}

/* Field-button (Display, Filters, etc.) */
.cmd-field-btn {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  height: 36px;
  padding: 0 12px;
  border-radius: 9px;
  border: 1px solid var(--line);
  background: var(--paper);
  color: var(--ink-2);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.1s, border-color 0.1s, color 0.1s;

  &:hover { border-color: var(--ink-3); }

  &.active {
    background: var(--brand-50);
    border-color: var(--brand);
    color: var(--brand-700);

    .chev { transform: rotate(180deg); }
  }

  .btn-icon { font-size: 16px; width: 16px; height: 16px; }
  .chev     { font-size: 16px; width: 16px; height: 16px; transition: transform 0.15s; }
}

/* Display menu wrapper */
.cmd-display-wrap {
  position: relative;
  flex-shrink: 0;
}

/* Display popover */
.display-popover {
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  z-index: 200;
  background: var(--paper);
  border: 1px solid var(--line);
  border-radius: 13px;
  box-shadow: 0 12px 32px rgba(28,27,34,.16), 0 2px 6px rgba(28,27,34,.08);
  padding: 8px 0;
  min-width: 260px;
  animation: lib-pop .12s ease;
}

.pop-section {
  padding: 8px 14px;
}

.pop-label {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  color: var(--ink-4);
  margin-bottom: 7px;
}

.pop-divider {
  border-top: 1px solid var(--line-2);
  margin: 4px 0;
}

/* Segmented controls */
.seg-group {
  display: flex;
  background: var(--chip);
  border-radius: 9px;
  padding: 3px;
  gap: 2px;
}

.seg-btn {
  flex: 1;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
  height: 30px;
  padding: 0 10px;
  border: none;
  border-radius: 7px;
  background: transparent;
  color: var(--ink-3);
  font-size: 12.5px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.1s, color 0.1s, box-shadow 0.1s;

  mat-icon { font-size: 15px; width: 15px; height: 15px; }

  &.seg-active {
    background: var(--paper);
    color: var(--ink);
    font-weight: 600;
    box-shadow: 0 1px 2px rgba(28,27,34,.12);
  }

  &:hover:not(.seg-active) { color: var(--ink-2); }
}

/* Columns checklist */
.col-checklist {
  display: flex;
  flex-direction: column;
  gap: 3px;
}

.col-check-item {
  display: flex;
  align-items: center;
  gap: 8px;
  font-size: 13px;
  color: var(--ink-2);
  cursor: pointer;
  padding: 3px 2px;
  border-radius: 5px;

  input[type="checkbox"] {
    width: 15px;
    height: 15px;
    accent-color: var(--brand);
    cursor: pointer;
    flex-shrink: 0;
  }

  &:hover { background: var(--chip); }
}

/* Spacer */
.cmd-spacer { flex: 1 1 auto; }

/* Icon buttons */
.cmd-icon-btn {
  width: 36px !important;
  height: 36px !important;
  border-radius: 9px !important;
  border: 1px solid var(--line) !important;
  color: var(--ink-2) !important;

  mat-icon { font-size: 19px; }

  &:hover { border-color: var(--ink-3) !important; }
}

/* Mat-select fields in command bar */
.cmd-field {
  height: 36px;
  flex-shrink: 0;

  ::ng-deep .mat-mdc-text-field-wrapper { background: var(--paper) !important; }
  ::ng-deep .mat-mdc-form-field-flex { height: 36px; }
