@use "../../../styles" as styles;

/* ── Design tokens ───────────────────────────────────────────────────────── */
:host {
  @include styles.page-component-layout;
  display: flex;
  flex-direction: column;
  height: 100%;
  overflow: hidden;
  font-family: 'Hanken Grotesk', system-ui, sans-serif;

  --ink:       #1c1b22;
  --ink-2:     #46454f;
  --ink-3:     #76747f;
  --ink-4:     #a8a6af;
  --line:      #e7e3dd;
  --line-2:    #f0ece6;
  --paper:     #ffffff;
  --bg:        #f5f3ef;
  --chip:      #f1eee9;
  --brand:     #3f3d86;
  --brand-700: #302e63;
  --brand-50:  #ecebf6;
  --accent:    #c2662f;
  --accent-700:#9a4f23;
  --accent-50: #f7ece2;
}

/* ── Command bar ─────────────────────────────────────────────────────────── */
.command-bar {
  display: flex;
  align-items: center;
  flex-wrap: wrap;
  gap: 8px;
  padding: 10px 20px;
  background: var(--paper);
  border-bottom: 1px solid var(--line);
  flex-shrink: 0;
  min-height: 56px;
  box-sizing: border-box;
}

.cmd-brand {
  display: flex;
  align-items: center;
  gap: 8px;
  flex-shrink: 0;
}

.brand-tile {
  width: 28px;
  height: 28px;
  border-radius: 8px;
  background: var(--brand);
  display: flex;
  align-items: center;
  justify-content: center;

  mat-icon {
    color: #fff;
    font-size: 16px;
    width: 16px;
    height: 16px;
  }
}

.brand-title {
  font-size: 15px;
  font-weight: 800;
  letter-spacing: -0.02em;
  color: var(--ink);
  white-space: nowrap;
}

.cmd-vr {
  width: 1px;
  height: 24px;
  background: var(--line);
  flex-shrink: 0;
  margin: 0 2px;
}

.cmd-create {
  background: var(--accent) !important;
  color: #fff !important;
  border-radius: 9px !important;
  height: 36px;
  padding: 0 14px;
  font-size: 13.5px;
  font-weight: 600;
  flex-shrink: 0;
  box-shadow: none !important;

  mat-icon {
    font-size: 18px;
    width: 18px;
    height: 18px;
    margin-right: 4px;
  }

  &:hover { background: var(--accent-700) !important; }
}

.cmd-search {
  flex: 1 1 180px;
  min-width: 150px;
  max-width: 360px;
}

/* Field-button (Display, Filters, etc.) */
.cmd-field-btn {
  display: inline-flex;
  align-items: center;
  gap: 5px;
  height: 36px;
  padding: 0 12px;
  border-radius: 9px;
  border: 1px solid var(--line);
  background: var(--paper);
  color: var(--ink-2);
  font-size: 13px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.1s, border-color 0.1s, color 0.1s;

  &:hover { border-color: var(--ink-3); }

  &.active {
    background: var(--brand-50);
    border-color: var(--brand);
    color: var(--brand-700);

    .chev { transform: rotate(180deg); }
  }

  .btn-icon { font-size: 16px; width: 16px; height: 16px; }
  .chev     { font-size: 16px; width: 16px; height: 16px; transition: transform 0.15s; }
}

/* Display menu wrapper */
.cmd-display-wrap {
  position: relative;
  flex-shrink: 0;
}

/* Display popover */
