  left: 0;
  z-index: 200;
  background: var(--paper);
  border: 1px solid var(--line);
  border-radius: 13px;
  box-shadow: 0 12px 32px rgba(28,27,34,.16), 0 2px 6px rgba(28,27,34,.08);
  padding: 8px 0;
  min-width: 260px;
  animation: lib-pop .12s ease;
}

.pop-section {
  padding: 8px 14px;
}

.pop-label {
  font-size: 10px;
  font-weight: 700;
  text-transform: uppercase;
  letter-spacing: 0.07em;
  color: var(--ink-4);
  margin-bottom: 7px;
}

.pop-divider {
  border-top: 1px solid var(--line-2);
  margin: 4px 0;
}

