.seg-group {
  display: flex;
  background: var(--chip);
  border-radius: 9px;
  padding: 3px;
  gap: 2px;
}

.seg-btn {
  flex: 1;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 5px;
  height: 30px;
  padding: 0 10px;
  border: none;
  border-radius: 7px;
  background: transparent;
  color: var(--ink-3);
  font-size: 12.5px;
  font-weight: 500;
  cursor: pointer;
  white-space: nowrap;
  transition: background 0.1s, color 0.1s, box-shadow 0.1s;

  mat-icon { font-size: 15px; width: 15px; height: 15px; }

