@use "../../../styles" as styles;

/* --- Layout Structure --- */
:host {
  @include styles.page-component-layout;
}

.item-toolbar {
  display: flex;
  align-items: center;
  padding: 0px 16px;
  background-color: #fff;
  border-bottom: 1px solid #e0e0e0;
  height: auto;
  min-height: 55px;
  box-sizing: border-box;
}

.toolbar-left, .toolbar-right {
  display: flex;
  align-items: center;
  gap: 12px; /* Consistent spacing between items */
}

.toolbar-spacer {
  flex: 1 1 auto; /* Pushes left and right sections apart */
}

/* --- Input & Dropdown Styling --- */

/* Force specific width on fields */
.compact-field {
  width: 160px;
}

.wide-field {
  width: 200px;
}

/* Overrides to make Outline fields look crisp and match button height */
::ng-deep .mat-mdc-form-field-flex {
  align-items: center !important;
  background-color: #fff !important;
}

::ng-deep .mat-mdc-text-field-wrapper {
  background-color: #fff !important;
}

/* Center the select value text vertically within the form field */
::ng-deep .toolbar-field {
  .mat-mdc-form-field-infix {
    display: flex;
    align-items: center;
    min-height: 40px;
  }

  .mat-mdc-select {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }

  .mat-mdc-select-value {
    display: flex;
    align-items: center;
    margin-bottom: 3px;
  }
}


/* --- Button Styling --- */

/* Primary Action (Pink) */
.create-btn {
  background-color: #D81B60 !important; /* Adjust to match your exact header pink */
  color: #fff !important;
  border-radius: 4px;
  height: 40px;
  padding: 0 20px;
  font-weight: 500;
  letter-spacing: 0.5px;
  box-shadow: 0 2px 5px rgba(0,0,0,0.1);

  mat-icon {
    margin-right: 6px;
  }
}

/* Secondary Action (Outline / Ghost) */
.secondary-btn {
  background-color: #fff !important;
  color: #37474f !important; /* Dark Slate text */
  border: 1px solid #cfd8dc !important;
  height: 40px;
  padding: 0 16px;
  border-radius: 4px;

  mat-icon {
    color: #546e7a;
    margin-right: 6px;
  }

}

/* Export button: nudge left so Reset Filters sits clearly to its right */
.export-btn {
  margin-right: 8px;
}

/* Search Component Wrapper */
.search-item {
  display: flex;
  align-items: center;
}


/* --- View Dropdown Internals (Custom Menu) --- */
.view-dropdown-actions {
  padding: 8px;
  border-top: 1px solid #eee;
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.view-btn-group {
  display: flex;
  justify-content: space-between;
}

.new-view-input {
  display: flex;
  gap: 8px;
  align-items: center;

  .view-input {
    border: 1px solid #ccc;
    padding: 6px;
    border-radius: 4px;
    width: 100%;
  }
}


/* --- Grid & Legacy Styles --- */
::ng-deep .ag-paging-panel {
    justify-content: center !important;
}

.ag-cell[col-id="pic"] {
  display: flex !important;
  align-items: center !important;
  justify-content: center !important;
}

.ag-cell[col-id="pic"] img {
  max-height: 100%;
  object-fit: contain;
  margin: auto;
  position: static !important;
}

/* Fix filter list text color in right sidebar - override pink theme's headerTextColor */
::ng-deep .ag-filter-toolpanel-group-level-0-header,
::ng-deep .ag-filter-toolpanel-group-level-0-header .ag-group-title,
::ng-deep .ag-filter-toolpanel-group-level-0-header .ag-group-title-bar,
::ng-deep .ag-filter-toolpanel-group-level-0-header-icon,
::ng-deep .ag-filter-toolpanel-group-level-0-header span,
::ng-deep .ag-filter-toolpanel-group-title {
  color: #7E2E84 !important; /* rgb(126, 46, 132) - purple color for better visibility */
}

::ng-deep .grid-wrapper {
  /* Add borders to all cells with explicit color */
  .ag-cell {
    border-right: 1px solid #e0e0e0 !important;
  }
  .ag-cell-focus
  {
    border: 1.5px solid #2196f3 !important;
  }
}

