import { describe, expect, test } from '@jest/globals';
import { readFileSync } from 'fs';
import { join } from 'path';

const TEMPLATE_PATH = join(__dirname, 'newItem-dialog.component.html');
const COMPONENT_PATH = join(__dirname, 'newItem-dialog.component.ts');

describe('newItem-dialog component wiring', () => {
  test('marks For Customer as required in the template', () => {
    const template = readFileSync(TEMPLATE_PATH, 'utf8');
    const forCustomerSection = template.slice(
      template.indexOf('For Customer'),
      template.indexOf('formControlName="forCustomerControl"') + 40,
    );

    expect(forCustomerSection).toContain('For Customer <span style="color: red">*</span>');
    expect(forCustomerSection).toContain('formControlName="forCustomerControl"');
  });

  test('uses extracted required-field helpers for create validation', () => {
    const source = readFileSync(COMPONENT_PATH, 'utf8');

    expect(source).toContain("from './newItem-required-fields'");
    expect(source).toContain('getNewItemMissingRequiredFieldMessage');
    expect(source).toContain('getNewItemDescriptionLengthError');
    expect(source).not.toContain('Please fill all required fields.');
  });
});

