import { describe, expect, it } from '@jest/globals';
import { trackingUrl } from './sample-cell-renderers';

describe('sample tracking renderers', () => {
  it('builds direct courier tracking links where supported', () => {
    expect(trackingUrl('ups', '1Z999')).toBe('https://www.ups.com/track?tracknum=1Z999');
    expect(trackingUrl('fedex', '123')).toBe('https://www.fedex.com/fedextrack/?trknbr=123');
  });

  it('uses the official AAE tracking page and a prefilled Bombino URL', () => {
    expect(trackingUrl('aae', 'ABC')).toBe('https://www.aae-global.com/tracking.aspx');
    expect(trackingUrl('bombino', 'ABC')).toBe('https://www.bombinoexp.com/tracking.php?searchselected=1&tracking_no=ABC');
  });
});

