import { Component } from '@angular/core';
import { ICellRendererAngularComp } from 'ag-grid-angular';
import { ICellRendererParams } from 'ag-grid-community';

function stringToHue(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return Math.abs(hash) % 360;
}

@Component({
  selector: 'app-property-cell',
  templateUrl: './property-cell.component.html',
  styleUrls: ['./property-cell.component.scss'],
  standalone: false
})
export class PropertyCellComponent implements ICellRendererAngularComp {
  label = '';
  dotColor = 'hsl(220 45% 52%)';

  agInit(params: ICellRendererParams): void {
    this.label = String(params.value || '');
    const hue = stringToHue(String(params.data?.property || params.data?.property_id || this.label));
    this.dotColor = `hsl(${hue} 45% 52%)`;
  }

  refresh(params: ICellRendererParams): boolean {
    this.agInit(params);
    return true;
  }
}

