/**
 * Shared pure helpers for the Item Library redesign cell renderers and views.
 *
 * Centralizes the status→tone mapping, the property→hue hashing, and the
 * thumbnail/field derivation so the thumbnail, status-pill, property-cell,
 * split-rail, and gallery components all stay in lockstep. Keep this module
 * free of Angular/DOM dependencies so it can be unit-tested in isolation.
 */

export interface PillTone {
  bg: string;
  fg: string;
  dot: string;
}

/** Stage key → pill tone (bg / fg / dot). Lifted from the approved Item Detail palette. */
export const STATUS_TONES: Record<string, PillTone> = {
  concept:    { bg: '#f1eee9', fg: '#46454f', dot: '#76747f' },
  design:     { bg: '#ecebf6', fg: '#302e63', dot: '#3f3d86' },
  submitted:  { bg: '#f7efe0', fg: '#8a6312', dot: '#c08a2a' },
  approved:   { bg: '#e8f1ea', fg: '#2f6a45', dot: '#3f8a5b' },
  sampling:   { bg: '#f7ece2', fg: '#9a4f23', dot: '#c2662f' },
  production: { bg: '#ecebf6', fg: '#302e63', dot: '#3f3d86' },
  shelf:      { bg: '#e8f1ea', fg: '#2f6a45', dot: '#3f8a5b' },
  discont:    { bg: '#f7e7e4', fg: '#9a3a30', dot: '#bd5246' },
};

/** Human status label (lowercased) → stage key into STATUS_TONES. */
export const STATUS_KEY_MAP: Record<string, string> = {
  'concept':      'concept',
  'in design':    'design',
  'submitted':    'submitted',
  'approved':     'approved',
  'in sampling':  'sampling',
  'production':   'production',
  'on shelf':     'shelf',
  'discontinued': 'discont',
};

/** Resolve a status label of any casing/whitespace to its pill tone; unknown → 'concept'. */
export function resolveStatusTone(status: string | null | undefined): PillTone {
  const key = STATUS_KEY_MAP[(status || '').toLowerCase().trim()] || 'concept';
  return STATUS_TONES[key];
}

/**
 * Deterministic string→hue hash (0–359). The same property always maps to the
 * same hue so the thumbnail tile, the color dot, and the gallery card agree.
 */
export function stringToHue(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return Math.abs(hash) % 360;
}

/** Hue source for an item: prefers the property name, falls back to property_id, then ''. */
export function propertyHue(item: any): number {
  return stringToHue(String(item?.property ?? item?.property_id ?? ''));
}

export function tileGradient(hue: number): string {
  return `linear-gradient(150deg, hsl(${hue} 46% 95%), hsl(${hue} 40% 87%))`;
}

export function tileBorderColor(hue: number): string {
  return `hsl(${hue} 30% 80%)`;
}

export function glyphColor(hue: number): string {
  return `hsl(${hue} 42% 34%)`;
}

export function propertyDotColor(hue: number): string {
  return `hsl(${hue} 45% 52%)`;
}

/** Pick the best available thumbnail URL for an item, or null when it has no image. */
export function resolveThumbSrc(item: any): string | null {
  return item?.pic?.Thumbnail || item?.pic?.FullSizePicture || null;
}

export interface RailField {
  label: string;
  value: string;
  mono?: boolean;
  full?: boolean;
}

const DASH = '—';

/** Build the ordered field list shown in the Split workspace preview rail. */
export function buildRailFields(item: any): RailField[] {
  if (!item) return [];
  return [
    { label: 'Item Num',     value: item.itemNum || DASH,                              mono: true },
    { label: 'Reference #',  value: item.refNum || DASH,                               mono: true },
    { label: 'Design #',     value: item.DSN || DASH,                                  mono: true },
    { label: 'Season',       value: item.season || DASH,                               mono: true },
    { label: 'Licensor',     value: item.licensorName || item.licensor || DASH,        full: true },
    { label: 'Product Type', value: item.materialName || item.material || DASH },
    { label: 'Sub-Type',     value: item.constructionName || item.construction || DASH },
    { label: 'Feature',      value: item.featureName || item.feature || DASH },
    { label: 'Size',         value: item.sizeName || item.size || DASH,                mono: true },
    { label: 'Division',     value: String(item.div_code_fk || DASH) },
  ];
}

/** Display name for the rail header. */
export function railItemName(item: any): string {
  return item?.item_name || item?.name || '';
}

/** "{property} · {material}" meta line for the rail header. */
export function railItemMeta(item: any): string {
  return [item?.propertyName || item?.property, item?.materialName || item?.material]
    .filter(Boolean)
    .join(' · ');
}

