import { ICellRendererParams } from 'ag-grid-community';
import { MatDialog } from '@angular/material/dialog';
import { HelperService } from 'src/app/helpers/services/helper.service';
import { ConfigService } from 'src/app/helpers/services/config.service';
import { imageEditorComponent } from '../imageEditor/imageEditor.component';

function stringToHue(str: string): number {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    hash = str.charCodeAt(i) + ((hash << 5) - hash);
  }
  return Math.abs(hash) % 360;
}

@Component({
  selector: 'app-item-thumbnail',
  templateUrl: './item-thumbnail.component.html',
  styleUrls: ['./item-thumbnail.component.scss'],
  standalone: false
})
export class ItemThumbnailComponent implements ICellRendererAngularComp {
  imgSrc: string | null = null;
  itemNum = '';
  propertyHue = 220;
  hasImage = false;

  constructor(
    private dialog: MatDialog,
    private helperService: HelperService,
    private configService: ConfigService
  ) {}

  agInit(params: ICellRendererParams): void {
    this.itemNum = params.data?.itemNum || '';
    this.propertyHue = stringToHue(String(params.data?.property || params.data?.property_id || ''));

    if (params.data?.pic?.Thumbnail) {
      this.imgSrc = this.helperService.buildPublicUrl(params.data.pic.Thumbnail);
      this.hasImage = true;
    } else if (params.data?.pic?.FullSizePicture) {
      this.imgSrc = this.helperService.buildPublicUrl(params.data.pic.FullSizePicture);
      this.hasImage = true;
    } else {
      this.imgSrc = null;
      this.hasImage = false;
    }
  }

  refresh(params: ICellRendererParams): boolean {
    this.agInit(params);
    return true;
  }

  onImageClick(): void {
    if (!this.hasImage) return;
    this.dialog.open(imageEditorComponent, {
      data: { FullSizePicture: this.imgSrc, Thumbnail: this.imgSrc },
      maxWidth: '95vw',
      maxHeight: '95vh'
    });
  }

  get tileGradient(): string {
    return `linear-gradient(150deg, hsl(${this.propertyHue} 46% 95%), hsl(${this.propertyHue} 40% 87%))`;
  }

  get tileBorderColor(): string {
    return `hsl(${this.propertyHue} 30% 80%)`;
  }

  get glyphColor(): string {
    return `hsl(${this.propertyHue} 42% 34%)`;
  }
}

