import { describe, expect, it, jest } from '@jest/globals';
import { GalleryComponent } from './gallery.component';
import { resolveStatusTone } from '../item-library-shared';

function makeComponent(): GalleryComponent {
  return new GalleryComponent();
}

describe('GalleryComponent', () => {
  it('reports selection based on the selectedIds set', () => {
    const c = makeComponent();
    c.selectedIds = new Set([1, 3]);
    expect(c.isSelected({ id: 1 })).toBe(true);
    expect(c.isSelected({ id: 2 })).toBe(false);
  });

  it('emits selectionChange with the item and checked flag', () => {
    const c = makeComponent();
    const spy = jest.fn();
    c.selectionChange.subscribe(spy);
    const item = { id: 5 };
    c.onCheck(item, true);
    expect(spy).toHaveBeenCalledWith({ item, checked: true });
  });

  it('emits itemOpen on double click', () => {
    const c = makeComponent();
    const spy = jest.fn();
    c.itemOpen.subscribe(spy);
    const item = { id: 9 };
    c.onDblClick(item);
    expect(spy).toHaveBeenCalledWith(item);
  });

  it('delegates status tone resolution to the shared helper', () => {
    const c = makeComponent();
    expect(c.getStatusTone('Approved')).toBe(resolveStatusTone('Approved'));
  });

  it('builds property-driven colors', () => {
    const c = makeComponent();
    const item = { property: 'Cosmic Cadets' };
    expect(c.getPropertyDot(item)).toMatch(/^hsl\(\d+ 45% 52%\)$/);
    expect(c.getTileGradient(item)).toContain('linear-gradient(150deg');
    expect(c.getTileBorder(item)).toMatch(/^1px solid hsl\(\d+ 30% 80%\)$/);
  });

  it('resolves thumbnail src with fallback', () => {
    const c = makeComponent();
    expect(c.getThumbSrc({ pic: { Thumbnail: 't.png' } })).toBe('t.png');
    expect(c.getThumbSrc({})).toBeNull();
  });
});

