import { describe, expect, it, jest } from '@jest/globals';
import { Router } from '@angular/router';
import { SplitRailComponent } from './split-rail.component';
import { STATUS_TONES } from '../item-library-shared';

function makeComponent(): { component: SplitRailComponent; navigate: jest.Mock } {
  const navigate = jest.fn();
  const router = { navigate } as unknown as Router;
  return { component: new SplitRailComponent(router), navigate };
}

describe('SplitRailComponent', () => {
  it('starts empty with no active item', () => {
    const { component } = makeComponent();
    expect(component.hasItem).toBe(false);
    expect(component.fields).toEqual([]);
    expect(component.statusTone).toBe(STATUS_TONES['concept']);
  });

  it('builds fields and resolves status tone when an item is set', () => {
    const { component } = makeComponent();
    component.item = { id: 1, status: 'Approved', itemNum: 'IT-1', item_name: 'Pip the Fox' };
    expect(component.hasItem).toBe(true);
    expect(component.statusLabel).toBe('Approved');
    expect(component.statusTone).toBe(STATUS_TONES['approved']);
    expect(component.fields.find(f => f.label === 'Item Num')!.value).toBe('IT-1');
    expect(component.itemName).toBe('Pip the Fox');
  });

  it('clears state when the item is set back to null', () => {
    const { component } = makeComponent();
    component.item = { id: 1, status: 'Approved' };
    component.item = null;
    expect(component.hasItem).toBe(false);
    expect(component.fields).toEqual([]);
    expect(component.statusLabel).toBe('');
    expect(component.statusTone).toBe(STATUS_TONES['concept']);
  });

  it('navigates to item detail on open when an item has an id', () => {
    const { component, navigate } = makeComponent();
    component.item = { id: 77 };
    component.onOpen();
    expect(navigate).toHaveBeenCalledWith(['/apps/itemDetail/77']);
  });

  it('does not navigate when there is no active item', () => {
    const { component, navigate } = makeComponent();
    component.onOpen();
    expect(navigate).not.toHaveBeenCalled();
  });
});

