import { describe, expect, it } from '@jest/globals';
import { ICellRendererParams } from 'ag-grid-community';
import { StatusPillComponent } from './status-pill.component';
import { STATUS_TONES } from '../item-library-shared';

function params(value: any): ICellRendererParams {
  return { value } as ICellRendererParams;
}

describe('StatusPillComponent', () => {
  it('sets the label and tone from the cell value', () => {
    const c = new StatusPillComponent();
    c.agInit(params('In Sampling'));
    expect(c.label).toBe('In Sampling');
    expect(c.tone).toBe(STATUS_TONES['sampling']);
  });

  it('falls back to the concept tone for an empty value', () => {
    const c = new StatusPillComponent();
    c.agInit(params(null));
    expect(c.label).toBe('');
    expect(c.tone).toBe(STATUS_TONES['concept']);
  });

  it('refresh re-applies state and returns true', () => {
    const c = new StatusPillComponent();
    c.agInit(params('Concept'));
    const result = c.refresh(params('Discontinued'));
    expect(result).toBe(true);
    expect(c.label).toBe('Discontinued');
    expect(c.tone).toBe(STATUS_TONES['discont']);
  });
});

