import { describe, expect, it } from '@jest/globals';
import { ICellRendererParams } from 'ag-grid-community';
import { PropertyCellComponent } from './property-cell.component';
import { propertyDotColor, stringToHue } from '../item-library-shared';

function params(value: any, data: any = {}): ICellRendererParams {
  return { value, data } as ICellRendererParams;
}

describe('PropertyCellComponent', () => {
  it('renders the property label', () => {
    const c = new PropertyCellComponent();
    c.agInit(params('Woodland Friends', { property: 'Woodland Friends' }));
    expect(c.label).toBe('Woodland Friends');
  });

  it('derives a stable dot color from the property', () => {
    const c = new PropertyCellComponent();
    c.agInit(params('Woodland Friends', { property: 'Woodland Friends' }));
    expect(c.dotColor).toBe(propertyDotColor(stringToHue('Woodland Friends')));
  });

  it('falls back to the label when row data has no property', () => {
    const c = new PropertyCellComponent();
    c.agInit(params('Tide Pool Pals', {}));
    expect(c.dotColor).toBe(propertyDotColor(stringToHue('Tide Pool Pals')));
  });

  it('handles an empty value without throwing', () => {
    const c = new PropertyCellComponent();
    c.agInit(params(null, {}));
    expect(c.label).toBe('');
    expect(c.dotColor).toMatch(/^hsl\(\d+ 45% 52%\)$/);
  });

  it('refresh re-applies and returns true', () => {
    const c = new PropertyCellComponent();
    c.agInit(params('Meadow Sprites', { property: 'Meadow Sprites' }));
    expect(c.refresh(params('Pixel Pups', { property: 'Pixel Pups' }))).toBe(true);
    expect(c.label).toBe('Pixel Pups');
  });
});

