  onRowMouseEnter: (event: any) => {
    if (this.layout !== 'filmstrip' || this.view !== 'table') return;
    this.ngZone.run(() => {
      this.hoverItem = event.data;
      const scrollRange = this.gridApi?.getVerticalPixelRange();
      this.hoverItemY = (event.node?.rowTop ?? 0) - (scrollRange?.top ?? 0) + 48;
    });
  },
  onRowMouseLeave: () => {
    if (!this.hoverItem) return;
    this.ngZone.run(() => { this.hoverItem = null; });
  },
};

